  ('social-worker-moex-03131', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據Garbarino & Abramowitz（1992）的看法，所謂「文化貧窮」（cultural impoverishment）的涵義是指：', '["忽略兒童健康發展的價值觀", "兒童生活中缺乏重要的社會資源", "父母無法獲得適當的社會支持", "幼兒受到不適當的刺激或教養"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03132', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在社會功能層面中，自助團體與其他團體的主要差異為何？', '["自助團體與一般團體的差異性不大", "自助團體最主要之目的在取得團體所需的相關資訊", "自助團體成員擁有自我管理、使用資源及決策的權力", "自助團體較強調自我的要求，且有一套協助成員的方法"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03133', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關「社會功能」的敘述何者錯誤？', '["「社會功能」協助社工員能聚焦於案主的轉變", "「社會功能」是指案主有能力去克服日常生活中所遭逢的問題", "「社會功能」是指案主能履行自己在社區中的主要社會角色", "「社會功能」是指案主能完成合理程度的要求，進而對社會有所貢獻"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03134', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '艾力克遜（Erickson）提出心理社會發展理論，其中「勤奮vs.自卑」是發生在人生那一個階段？', '["幼兒期", "兒童期", "中年期", "老年期"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03135', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '1953年由Virginia Apgar所發展的亞培格量表（Apgar Scale）是一般判定新生兒健康的量表，下列那一項 是其量表判定的完整指標？', '["脈搏、呼吸、活動、膚色、排泄", "脈搏、呼吸、活動、排泄、反射反應", "脈搏、心跳、膚色、活動、反射反應", "脈搏、呼吸、活動、膚色、反射反應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03136', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關唐氏症兒童的描述，下列何者錯誤？', '["唐氏症是一種症候群，與染色體異常無關", "唐氏症兒童生長較為遲緩、壽命比正常人短，主要的問題是智能障礙", "唐氏症兒童常會伴隨先天性心臟病、先天性腸胃道畸形、視力、聽力缺損等", "唐氏症的發生率與母親生育的年齡有相當大的關係"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03137', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '由人文學派Thomas Gordon所創的父母效能訓練（PET）處遇策略中，下列那一項是正確的描述？', '["父母需要多用威權才能從小把孩子管教好", "父母應強調一致性的管教原則，才不會造成親子衝突", "父母應多使用「我的訊息」和孩子進行表達和溝通", "父母只需重視孩子的行為結果給予獎賞，不需重視其想法和動機"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03138', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列那一項對懷孕期的描述錯誤？', '["懷孕婦女的情緒反應並不會透過胎盤影響胎兒的發展", "懷孕期間吸菸婦女的胎兒出生體重比不吸菸婦女的胎兒來得輕", "貧窮是影響胎兒生存的心理和社會因素", "從受孕的那一刻開始，父母親的基因就影響胎兒的發展"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03139', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '嬰兒的發展是有目的性的動作發展，具有發展的原則，下列那一項是正確的發展原則？', '["從頭到尾的發展原則，又稱頭尾定律", "從複雜到簡單的發展模式", "從小肌肉到大肌肉的發展原則", "由遠至近的動作發展原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-03140', 'social-worker', 'social-worker-moex-100-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關婦女產後憂鬱症的敘述何者錯誤？', '["產生原因與荷爾蒙失調或過度疲勞有關", "一般症狀會在幾天或幾週內消失", "有時症狀會持續幾個月", "一般症狀是在生產後8週內出現"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:15+00:00", "source_pdf_sha1": "e30518f435ea", "answer_pdf_sha1": "d92305120445", "source_family": "moex-gov-tw", "moex": {"exam_code": "100160", "c": "902", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "100", "exam_name": "100年專門職業及技術人員高等考試會計師、社會工作師、不動產估價師、專利師、律師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
